// Normalize and clean job data from LinkedIn scraper
const results = [];

for (const item of $input.all()) {
  const j = item.json;

  const url = (j.jobUrl || j.url || j.link || '').trim();
  const title = j.title || j.jobTitle || j.position || '';
  const company = j.company || j.companyName || '';
  const location = j.location || j.jobLocation || '';
  const description = j.description || j.jobDescription || j.descriptionHtml || '';

  if (!url || !title || !description || description.length < 100) {
    continue;
  }

  results.push({
    json: {
      url,
      title,
      company,
      location,
      description
    }
  });
}

console.log(`Jobs after normalization: ${results.length}`);
return results;

// Filter duplicate job URLs based on normalized data
const normalizeUrl = (url = '') => url.toString().split('?')[0].replace(/\/$/, '').trim().toLowerCase();
const normalizeText = (v = '') => v.toString().trim().toLowerCase();

const existing = new Set();

let sheetRows = [];
try {
  sheetRows = $('Get Existing Jobs').all();
} catch (e) {
  sheetRows = [];
}

for (const row of sheetRows) {
  const r = row.json || {};
  const url = r.URL || r.Url || r.url || '';

  if (!url) continue;

  const key = [
    normalizeUrl(url),
    normalizeText(r.Company || r.company || ''),
    normalizeText(r.Role || r.role || '')
  ].join('|');

  existing.add(key);
}

const output = [];

for (const item of $input.all()) {
  const job = item.json || {};

  if (!job.url || !job.title) continue;

  const key = [
    normalizeUrl(job.url),
    normalizeText(job.company || ''),
    normalizeText(job.title)
  ].join('|');

  if (existing.has(key)) {
    console.log(`Duplicate skipped: ${job.title} @ ${job.company}`);
    continue;
  }

  output.push({ json: job });
}

console.log(`New unique jobs after dedup: ${output.length}`);
return output;

// Build LLM payload for relocation analysis
const results = [];

for (const item of $input.all()) {
  const job = item.json;

  const trimmedDescription = (job.description || '');

  const payload = {
    model: 'unsloth/Qwen3.5-9B-GGUF:Q6_K',
    temperature: 0.1,
    max_tokens: 10000,
    top_p: 0.9,
    repeat_penalty: 1.05,
    stop: ['\n\n', '</s>'],
    messages: [
      {
        role: 'system',
        content: `You are an expert technical recruiter.

Analyze whether this job is suitable for an Indian software engineer relocating to the Netherlands.

Return ONLY valid JSON.

Rules:
- approve=true if the role likely supports visa sponsorship, relocation, kennismigrant hiring, or international candidates.
- approve=false if the role clearly requires Dutch only, EU citizenship, existing work authorization, or explicitly says no sponsorship.
- confidence should be: high, medium, or low.
- reason should be short.

JSON format:
{
  "approve": true,
  "confidence": "high",
  "reason": "mentions visa sponsorship"
}`
      },
      {
        role: 'user',
        content: `Job Title: ${job.title}
Company: ${job.company}
Location: ${job.location}

Description:
${trimmedDescription}`
      }
    ],
    extra_body: {
      chat_template_kwargs: {
        enable_thinking: false
      }
    }
  };

  results.push({
    json: {
      ...job,
      _relocationPayload: payload
    }
  });
}

return results;

